namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; }
    public DateTime? UpdatedAt { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Client.Models;

public class CreateShipmentRequest
{
    [Required, StringLength(200)]
    public string Origin { get; set; } = string.Empty;

    [Required, StringLength(200)]
    public string Destination { get; set; } = string.Empty;

    [Required, StringLength(100)]
    public string RecipientName { get; set; } = string.Empty;

    [StringLength(500)]
    public string Description { get; set; } = string.Empty;

    public DateTime? EstimatedDelivery { get; set; }
}

namespace ShipmentTracker.Client.Models;

public class UpdateShipmentStatusRequest
{
    public ShipmentStatus Status { get; set; }
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null, string? search = null);
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> GetShipmentByIdAsync(int id);
    Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request);
    Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, UpdateShipmentStatusRequest request);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null, string? search = null)
    {
        var query = new List<string>();
        if (!string.IsNullOrWhiteSpace(statusFilter))
            query.Add($"status={Uri.EscapeDataString(statusFilter)}");
        if (!string.IsNullOrWhiteSpace(search))
            query.Add($"search={Uri.EscapeDataString(search)}");

        var url = "api/shipments";
        if (query.Count > 0)
            url += "?" + string.Join("&", query);

        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var response = await http.GetAsync($"api/shipments/{id}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var response = await http.PostAsJsonAsync("api/shipments", request);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }

    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, UpdateShipmentStatusRequest request)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", request);
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }
}

