using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null, string? search = null)
    {
        var query = db.Shipments.AsQueryable();

        if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, true, out var status))
            query = query.Where(s => s.Status == status);

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(s =>
                s.TrackingNumber.Contains(search) ||
                s.Destination.Contains(search) ||
                s.RecipientName.Contains(search) ||
                s.Origin.Contains(search));

        return await query
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = request.Origin,
            Destination = request.Destination,
            RecipientName = request.RecipientName,
            Description = request.Description,
            EstimatedDelivery = request.EstimatedDelivery,
            Status = ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, UpdateShipmentStatusRequest request)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return null;

        shipment.Status = request.Status;
        shipment.UpdatedAt = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description,
        CreatedAt = s.CreatedAt,
        UpdatedAt = s.UpdatedAt
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (string? status, string? search, IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync(status, search)));

        group.MapGet("/{id:int}", async (int id, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByIdAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Tracking endpoint is publicly accessible
        app.MapGet("api/shipments/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapPost("/", async (CreateShipmentRequest request, IShipmentService service) =>
        {
            var shipment = await service.CreateShipmentAsync(request);
            return Results.Created($"api/shipments/{shipment.Id}", shipment);
        });

        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, IShipmentService service) =>
        {
            var shipment = await service.UpdateShipmentStatusAsync(id, request);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });
    }
}

