+{
+    public static void MapShipmentEndpoints(this WebApplication app)
+    {
+        var group = app.MapGroup("api/shipments").RequireAuthorization();
+
+        group.MapGet("/", async (string? status, string? search, IShipmentService service) =>
+            Results.Ok(await service.GetAllShipmentsAsync(status, search)));
+
+        group.MapGet("/{id:int}", async (int id, IShipmentService service) =>
+        {
+            var shipment = await service.GetShipmentByIdAsync(id);
+            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
+        });
+
+        // Tracking endpoint is publicly accessible
+        app.MapGet("api/shipments/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
+        {
+            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
+            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
+        });
+
+        group.MapPost("/", async (CreateShipmentRequest request, IShipmentService service) =>
+        {
+            var shipment = await service.CreateShipmentAsync(request);
+            return Results.Created($"api/shipments/{shipment.Id}", shipment);
+        });
+
+        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, IShipmentService service) =>
+        {
+            var shipment = await service.UpdateShipmentStatusAsync(id, request);
+            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
+        });
+    }
+}
