@page "/"

<PageTitle>ShipmentTracker — Home</PageTitle>

<div class="container mt-4">
    <div class="text-center mb-5">
        <h1 class="display-4">📦 Shipment Tracker</h1>
        <p class="lead text-muted">Track your shipments in real time</p>
    </div>

    <div class="row justify-content-center mb-5">
        <div class="col-md-8">
            <div class="card shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">Track a Shipment</h5>
                    <div class="input-group">
                        <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260501-100001)"
                               @bind="trackingNumber" @bind:event="oninput"
                               @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isSearching">
                            @if (isSearching)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Track
                        </button>
                    </div>
                    @if (searchError is not null)
                    {
                        <div class="alert alert-warning mt-3 mb-0">@searchError</div>
                    }
                    @if (trackedShipment is not null)
                    {
                        <div class="card mt-3 border-success">
                            <div class="card-body">
                                <h6>@trackedShipment.TrackingNumber</h6>
                                <div class="row">
                                    <div class="col-sm-6">
                                        <strong>From:</strong> @trackedShipment.Origin<br />
                                        <strong>To:</strong> @trackedShipment.Destination
                                    </div>
                                    <div class="col-sm-6">
                                        <strong>Status:</strong>
                                        <span class="badge @GetStatusBadge(trackedShipment.Status)">@trackedShipment.Status</span><br />
                                        <strong>Est. Delivery:</strong>
                                        @(trackedShipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")
                                    </div>
                                </div>
                            </div>
                        </div>
                    }
                </div>
            </div>
        </div>
    </div>

    <AuthorizeView>
        <Authorized>
            <div class="text-center">
                <a href="shipments" class="btn btn-outline-primary btn-lg">
                    Go to Dispatch Dashboard →
                </a>
            </div>
        </Authorized>
        <NotAuthorized>
            <div class="text-center text-muted">
                <p><a href="Account/Login">Log in</a> to access the dispatch dashboard.</p>
            </div>
        </NotAuthorized>
    </AuthorizeView>
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private string trackingNumber = string.Empty;
    private ShipmentDto? trackedShipment;
    private string? searchError;
    private bool isSearching;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchError = null;
        trackedShipment = null;

        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        if (trackedShipment is null)
            searchError = "No shipment found with that tracking number.";

        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

