@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Dispatch Dashboard</PageTitle>

<div class="container-fluid mt-4">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>📋 Dispatch Dashboard</h2>
        <button class="btn btn-success" @onclick="() => showCreateForm = true" disabled="@showCreateForm">
            + New Shipment
        </button>
    </div>

    @if (showCreateForm)
    {
        <div class="card mb-4 border-primary">
            <div class="card-header bg-primary text-white">Create New Shipment</div>
            <div class="card-body">
                <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="create-shipment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />
                    <div class="row g-3">
                        <div class="col-md-6">
                            <label class="form-label">Origin</label>
                            <InputText class="form-control" @bind-Value="newShipment.Origin" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Destination</label>
                            <InputText class="form-control" @bind-Value="newShipment.Destination" />
                        </div>
