<PageTitle>Dispatch Dashboard</PageTitle>

<div class="container-fluid mt-4">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>📋 Dispatch Dashboard</h2>
        <button class="btn btn-success" @onclick="() => showCreateForm = true" disabled="@showCreateForm">
            + New Shipment
        </button>
    </div>

    @if (showCreateForm)
    {
        <div class="card mb-4 border-primary">
            <div class="card-header bg-primary text-white">Create New Shipment</div>
            <div class="card-body">
                <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="create-shipment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />
                    <div class="row g-3">
                        <div class="col-md-6">
                            <label class="form-label">Origin</label>
                            <InputText class="form-control" @bind-Value="newShipment.Origin" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Destination</label>
                            <InputText class="form-control" @bind-Value="newShipment.Destination" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Recipient Name</label>
                            <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Description</label>
                            <InputText class="form-control" @bind-Value="newShipment.Description" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Est. Delivery</label>
                            <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                        </div>
                    </div>
                    <div class="mt-3">
                        <button type="submit" class="btn btn-primary" disabled="@isCreating">
                            @if (isCreating)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Create
                        </button>
                        <button type="button" class="btn btn-outline-secondary ms-2" @onclick="CancelCreate">Cancel</button>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    <div class="row g-3 mb-3">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Search by tracking #, destination, recipient..."
                   @bind="searchTerm" @bind:event="oninput" @bind:after="LoadShipments" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
                <option value="">All Statuses</option>
                @foreach (var s in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@s">@s</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="LoadShipments">
                🔄 Refresh
            </button>
        </div>
    </div>

    @if (isLoading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary"></div>
            <p class="mt-2">Loading shipments…</p>
        </div>
    }
    else if (shipments is null || shipments.Count == 0)
    {
        <div class="alert alert-info">No shipments found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Recipient</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var shipment in shipments)
                    {
                        <tr>
                            <td><code>@shipment.TrackingNumber</code></td>
                            <td>@shipment.Origin</td>
                            <td>@shipment.Destination</td>
                            <td>@shipment.RecipientName</td>
                            <td>
                                <span class="badge @GetStatusBadge(shipment.Status)">@shipment.Status</span>
                            </td>
                            <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>
                                @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                {
                                    <div class="input-group input-group-sm" style="max-width: 220px;">
                                        <select class="form-select form-select-sm"
                                                @bind="shipment.Status" @bind:after="() => UpdateStatus(shipment)">
                                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                            {
                                                <option value="@s">@s</option>
                                            }
                                        </select>
                                    </div>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private List<ShipmentDto>? shipments;
    private bool isLoading = true;
    private bool isCreating;
    private bool showCreateForm;
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;
    private CreateShipmentRequest newShipment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync(
            string.IsNullOrWhiteSpace(statusFilter) ? null : statusFilter,
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm);
        isLoading = false;
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new();
        showCreateForm = false;
        isCreating = false;
        await LoadShipments();
    }

    private void CancelCreate()
    {
        showCreateForm = false;
        newShipment = new();
    }

    private async Task UpdateStatus(ShipmentDto shipment)
    {
        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id,
            new UpdateShipmentStatusRequest { Status = shipment.Status });
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
