toolArgs.file_text:
@page "/track"

<PageTitle>Track Shipment</PageTitle>

<div class="container mt-4">
    <h2 class="mb-4">🔍 Track Your Shipment</h2>

    <div class="row justify-content-center">
        <div class="col-md-8">
            <div class="input-group mb-4">
                <input type="text" class="form-control form-control-lg"
                       placeholder="Enter your tracking number"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary btn-lg" @onclick="Search" disabled="@isSearching">
                    @if (isSearching)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Track
                </button>
            </div>

            @if (errorMessage is not null)
            {
                <div class="alert alert-warning">@errorMessage</div>
            }

            @if (shipment is not null)
            {
                <div class="card shadow">
                    <div class="card-header bg-dark text-white">
                        <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
                    </div>
                    <div class="card-body">
                        <div class="row mb-3">
                            <div class="col-sm-4 fw-bold">Status</div>
                            <div class="col-sm-8">
                                <span class="badge fs-6 @GetStatusBadge(shipment.Status)">@shipment.Status</span>
                            </div>
                        </div>
                        <div class="row mb-3">
                            <div class="col-sm-4 fw-bold">Origin</div>
                            <div class="col-sm-8">@shipment.Origin</div>
                        </div>
                        <div class="row mb-3">
                            <div class="col-sm-4 fw-bold">Destination</div>
                            <div class="col-sm-8">@shipment.Destination</div>
                        </div>
                        <div class="row mb-3">
                            <div class="col-sm-4 fw-bold">Recipient</div>
                            <div class="col-sm-8">@shipment.RecipientName</div>
                        </div>
                        @if (!string.IsNullOrWhiteSpace(shipment.Description))
                        {
                            <div class="row mb-3">
                                <div class="col-sm-4 fw-bold">Description</div>
                                <div class="col-sm-8">@shipment.Description</div>
                            </div>
                        }
                        <div class="row mb-3">
                            <div class="col-sm-4 fw-bold">Estimated Delivery</div>
                            <div class="col-sm-8">
                                @if (shipment.EstimatedDelivery.HasValue)
                                {
                                    var eta = shipment.EstimatedDelivery.Value;
                                    var daysLeft = (eta.Date - DateTime.UtcNow.Date).Days;
                                    <span>
                                        @eta.ToString("dddd, MMM dd, yyyy")
                                        @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                        {
                                            if (daysLeft > 0)
                                            {
                                                <span class="text-muted"> (@daysLeft day@(daysLeft != 1 ? "s" : "") away)</span>
                                            }
                                            else if (daysLeft == 0)
                                            {
                                                <span class="text-success fw-bold"> (Today!)</span>
                                            }
                                            else
                                            {
                                                <span class="text-danger"> (Overdue)</span>
                                            }
                                        }
                                    </span>
                                }
                                else
                                {
                                    <span class="text-muted">To be determined</span>
                                }
                            </div>
                        </div>
                        <div class="row mb-3">
                            <div class="col-sm-4 fw-bold">Shipped On</div>
                            <div class="col-sm-8">@shipment.CreatedAt.ToString("MMM dd, yyyy h:mm tt") UTC</div>
                        </div>
                        @if (shipment.UpdatedAt.HasValue)
                        {
                            <div class="row">
                                <div class="col-sm-4 fw-bold">Last Updated</div>
                                <div class="col-sm-8">@shipment.UpdatedAt.Value.ToString("MMM dd, yyyy h:mm tt") UTC</div>
                            </div>
                        }
                    </div>

                    @* Progress indicator *@
                    <div class="card-footer">
                        <div class="d-flex justify-content-between text-center">
                            @foreach (var step in progressSteps)
                            {
                                var isActive = (int)shipment.Status >= step.order;
                                <div class="flex-fill">
                                    <div class="rounded-circle d-inline-flex align-items-center justify-content-center @(isActive ? "bg-success text-white" : "bg-light text-muted")"
                                         style="width:32px;height:32px;">
                                        @step.icon
                                    </div>
                                    <div class="small mt-1 @(isActive ? "fw-bold" : "text-muted")">@step.label</div>
                                </div>
                            }
                        </div>
                    </div>
                </div>
            }
        </div>
    </div>
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isSearching;

    private readonly (int order, string icon, string label)[] progressSteps =
    [
        (0, "📝", "Pending"),
        (1, "📦", "Picked Up"),
        (2, "🚚", "In Transit"),
        (3, "🏠", "Out for Delivery"),
        (4, "✅", "Delivered")
    ];

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        errorMessage = null;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        if (shipment is null)
            errorMessage = "No shipment found. Please check the tracking number and try again.";

        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
